import click
import pandas as pd
import json

@click.command()
@click.option('--csv-file', required=True, help='Path to the CSV file.')
@click.option('--json-file', required=True, help='Path to the output JSON file.')
@click.option('--chunksize', default=100000, help='Number of rows to read at a time.')
def csv_to_json(csv_file, json_file, chunksize):
    """Converts a large CSV file to JSON using streaming."""
    with open(json_file, 'w') as f:
        f.write('[
')
        first_chunk = True
        for chunk in pd.read_csv(csv_file, chunksize=chunksize):
            json_records = chunk.to_json(orient='records')
            if not first_chunk:
                f.write(',
')
            else:
                first_chunk = False
            f.write(json_records)
        f.write('
]
')

if __name__ == '__main__':
    csv_to_json()
